complete_examples.code:
def add(a, b):
    """Add two numbers and return the result"""
    result = a + b
    return result

def subtract(a, b):
    return a - b

def multiply(a, b):
    return a * b

def divide(a, b):
    if b != 0:
        return a / b
    else:
        return 'Cannot divide by zero!'

# Use the calculator
print(f'10 + 5 = {add(10, 5)}')
print(f'10 - 5 = {subtract(10, 5)}')
print(f'10 × 5 = {multiply(10, 5)}')
print(f'10 ÷ 5 = {divide(10, 5)}')
print(f'10 ÷ 0 = {divide(10, 0)}')

def calculate_area(width, height):
    """Calculate rectangle area"""
    return width * height

def calculate_perimeter(width, height):
    """Calculate rectangle perimeter"""
    return 2 * (width + height)

def describe_rectangle(width, height):
    """Give complete information about a rectangle"""
    area = calculate_area(width, height)  # Calls another function
    perimeter = calculate_perimeter(width, height)  # Calls another function

    description = f"""
Rectangle Information:
- Width: {width}
- Height: {height}
- Area: {area}
- Perimeter: {perimeter}
    """
    return description

# One function does it all by using helper functions
print(describe_rectangle(10, 5))
print(describe_rectangle(8, 3))

def is_valid_age(age):
    """Check if age is a valid positive number"""
    if age < 0:
        return False
    elif age > 150:
        return False
    else:
        return True

def is_valid_email(email):
    """Simple email validation"""
    if '@' in email and '.' in email:
        return True
    else:
        return False

def process_user(name, age, email):
    """Process user data with validation"""
    if not is_valid_age(age):
        return 'Error: Invalid age!'

    if not is_valid_email(email):
        return 'Error: Invalid email!'

    return f'Welcome, {name}! Age: {age}, Email: {email}'

# Test with different inputs
print(process_user('Alice', 25, 'alice@email.com'))
print(process_user('Bob', -5, 'bob@email.com'))
print(process_user('Charlie', 30, 'charlie.email.com'))

def find_largest(numbers):
    """Find the largest number in a list"""
    if not numbers:
        return None

    largest = numbers[0]
    for num in numbers:
        if num > largest:
            largest = num
    return largest

def calculate_average(numbers):
    """Calculate average of numbers in a list"""
    if not numbers:
        return 0

    total = sum(numbers)
    average = total / len(numbers)
    return average

def analyze_list(numbers):
    """Analyze a list of numbers"""
    return {
        'count': len(numbers),
        'largest': find_largest(numbers),
        'smallest': min(numbers),
        'average': calculate_average(numbers),
        'total': sum(numbers)
    }

# Analyze some data
scores = [85, 92, 78, 90, 88, 95, 82]
analysis = analyze_list(scores)

print('Score Analysis:')
for key, value in analysis.items():
    print(f'  {key.capitalize()}: {value}')

def count_words(text):
    """Count words in a text"""
    words = text.split()
    return len(words)

def count_vowels(text):
    """Count vowels in a text"""
    vowels = 'aeiouAEIOU'
    count = 0
    for char in text:
        if char in vowels:
            count += 1
    return count

def reverse_text(text):
    """Reverse a text string"""
    return text[::-1]

def analyze_text(text):
    """Complete text analysis"""
    return {
        'characters': len(text),
        'words': count_words(text),
        'vowels': count_vowels(text),
        'reversed': reverse_text(text)
    }

# Analyze some text
text = 'Python is awesome'
analysis = analyze_text(text)

print(f'Text: "{text}"')
print('\nAnalysis:')
for key, value in analysis.items():
    print(f'  {key.capitalize()}: {value}')

