def find_max(a, b, c):
    if a >= b and a >= c:
        return a
    elif b >= c:
        return b
    else:
        return c

# Or simpler:
# def find_max(a, b, c):
#     return max(a, b, c)

print(find_max(10, 5, 8))
print(find_max(3, 9, 7))
print(find_max(15, 12, 20))

def get_grade(score):
    if score >= 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    else:
        return 'F'

print(get_grade(95))
print(get_grade(82))
print(get_grade(75))
print(get_grade(65))
print(get_grade(50))
